from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English paragraph. Handles mission/crewMembers aggregation to
    produce compact sentences.
    """
    if not triples:
        return ""

    # ---------- Helper utilities ----------
    def fmt_date(d: str) -> str:
        try:
            from datetime import datetime
            dt = datetime.strptime(d, "%Y-%m-%d")
            # Use platform‑independent day format
            return dt.strftime("%B %-d, %Y") if hasattr(dt, "strftime") else dt.strftime("%B %d, %Y")
        except Exception:
            return d

    def join_names(names: list[str]) -> str:
        """Join a list of names with commas and 'and'."""
        if not names:
            return ""
        if len(names) == 1:
            return names[0]
        if len(names) == 2:
            return f"{names[0]} and {names[1]}"
        return f"{', '.join(names[:-1])}, and {names[-1]}"

    # ---------- Phrase builder ----------
    def phrase(subj: str, pred: str, obj: str) -> str:
        obj = obj.strip().strip('"')
        p = pred.lower().replace(" ", "")
        if p == "birthdate":
            return f"was born on {fmt_date(obj)}"
        if p == "birthplace":
            return f"was born in {obj}"
        if p == "deathdate":
            return f"died on {fmt_date(obj)}"
        if p == "deathplace":
            return f"died in {obj}"
        if p == "nationality":
            low = obj.lower()
            if low in ("united states", "usa", "united states of america"):
                return "is an American"
            return f"is from {obj}"
        if p == "occupation":
            return f"served as a {obj.lower()}"
        if p == "status":
            low = obj.lower()
            if low == "retired":
                return "is now retired"
            return f"is {low}"
        if p == "selectedbynasa":
            return f"was selected by NASA in {obj}"
        if p == "timeinspace":
            try:
                mins = float(obj)
                hrs = int(mins // 60)
                rem = int(mins % 60)
                parts = []
                if hrs:
                    parts.append(f"{hrs} hour{'s' if hrs != 1 else ''}")
                if rem:
                    parts.append(f"{rem} minute{'s' if rem != 1 else ''}")
                return "spent " + " and ".join(parts) + " in space"
            except Exception:
                return f"spent {obj} minutes in space"
        if p == "title":
            return f"held the title of {obj}"
        if p == "award":
            return f"received the {obj}"
        if p == "awards":
            return f"received {obj} awards"
        if p == "ribbonaward":
            return f"was awarded the {obj}"
        if p == "operator":
            return f"was operated by {obj}"
        if p == "commander":
            return f"{obj} was the commander of {subj}"
        if p == "backuppilot":
            return f"{subj}'s backup pilot was {obj}"
        if p == "alternativename":
            return f"is also known as {obj}"
        if p == "servedaschiefoftheastronautofficein":
            return f"served as Chief of the Astronaut Office in {obj}"
        if p == "representative":
            return f"{obj} was the representative of {subj}"
        if p == "bird":
            return f"The {obj.lower()} is a bird found in {subj}"
        if p == "fossil":
            return f"{obj} is a fossil from {subj}"
        if p == "part":
            return f"{subj} is part of {obj}"
        if p == "partstype":
            return f"{subj} is {obj.lower()}"
        # generic fallback
        return f"is {obj}"

    # ---------- Aggregate mission/crew data ----------
    from collections import defaultdict

    # Collect mission‑related information in a single structure
    mission_info: dict[str, dict] = defaultdict(
        lambda: {"astronauts": [], "crew": [], "commander": [], "backupPilot": []}
    )
    other_triples: list[Triple] = []

    for t in triples:
        p = t.predicate.lower().replace(" ", "")
        if p == "mission":
            # subject is astronaut, object is mission name
            mission_info[t.object]["astronauts"].append(t.subject)
        elif p == "crewmembers":
            # subject is mission, object is crew member name
            mission_info[t.subject]["crew"].append(t.object)
        elif p == "commander":
            # object is commander name for the mission (subject is mission)
            mission_info[t.subject]["commander"].append(t.object)
        elif p == "backuppilot":
            mission_info[t.subject]["backupPilot"].append(t.object)
        else:
            other_triples.append(t)

    sentences: list[str] = []

    # Build a compact sentence for each mission
    for mission, info in mission_info.items():
        parts: list[str] = []

        # commander(s)
        if info["commander"]:
            parts.append(join_names(info["commander"]) + " was the commander")
        # backup pilot(s)
        if info["backupPilot"]:
            parts.append(join_names(info["backupPilot"]) + " was the backup pilot")
        # crew members (explicit crewMembers predicate)
        if info["crew"]:
            parts.append(join_names(info["crew"]) + " were crew members")
        # astronauts linked via the generic 'mission' predicate (often overlaps)
        if info["astronauts"]:
            # avoid duplication with already listed names
            remaining = [a for a in info["astronauts"] if a not in info["crew"] + info["commander"] + info["backupPilot"]]
            if remaining:
                parts.append(join_names(remaining) + " participated in")

        if parts:
            # join parts with commas and an "and" before the last element
            if len(parts) == 1:
                sentence = f"{parts[0]} of {mission}."
            else:
                sentence = f"{', '.join(parts[:-1])}, and {parts[-1]} of {mission}."
            sentences.append(sentence)

    # Process remaining triples (those not mission/crewMembers)
    # Group by subject
    groups = defaultdict(list)
    for t in other_triples:
        groups[t.subject].append(t)

    for subj, items in groups.items():
        descriptors = [phrase(subj, t.predicate, t.object) for t in items]
        if not descriptors:
            continue
        if len(descriptors) == 1:
            sentences.append(f"{subj} {descriptors[0]}.")
        else:
            body = ", ".join(descriptors[:-1])
            sentences.append(f"{subj} {body}, and {descriptors[-1]}.")
    return " ".join(sentences)

# EVOLVE-BLOCK-END

